:root{--track-mono:.1em}
.f-rail .f-conf{font-family:"Fira Code",monospace; font-size:.68rem; letter-spacing:var(--track-mono); text-transform:uppercase; color:var(--tx-2); line-height:1.5}
.f-engages .fe-label{letter-spacing:var(--track-mono)}
ul.plain.dropped .dc-label{letter-spacing:var(--track-mono)}
.mast-meta .mm-label{letter-spacing:var(--track-mono)}

/* renderFinding, lines 916–917 */
item.appendChild(document.createTextNode(shortName(r.principle)+" "));
var grp=el("span","fe-relgrp");
grp.appendChild(document.createTextNode("— "));
grp.appendChild(el("span","fe-rel "+rm.cls, rm.label));
item.appendChild(grp);
/* CSS */
.fe-relgrp{white-space:nowrap}
.f-engages .fe-item{display:block; padding-left:.65rem; text-indent:-.65rem}

/* renderFinding rail (line ~905) */
var rh=el("div","f-railhead"); rh.appendChild(star);
rh.appendChild(el("span","f-id",String(f.id||"")));
rail.appendChild(rh);
/* CSS */
.f-railhead{display:flex; align-items:center; gap:.5rem}
.f-id{font:500 .66rem/1 "Fira Code",monospace; letter-spacing:.14em; color:var(--tx-2); text-transform:uppercase}
/* dropped builder (lines 1111–1112) */
var m=/^merged_into:(.+)$/.exec(String(d.reason||""));
if(m && document.getElementById("f-"+m[1])){
  dc.appendChild(el("span","dc-label","reason "));
  var a=el("a",null,"merged into "+m[1]); a.href="#f-"+m[1]; dc.appendChild(a);
}else{ /* existing text path */ }
/* CSS */ .dc a{color:inherit; text-decoration:underline; text-underline-offset:2px}
.dc a:hover{color:var(--accent)}

/* renderFinding (line 906) */
var star=el("a","f-star","✴"); star.href="#f-"+f.id;
star.setAttribute("aria-label","Link to this finding ("+f.id+")");
/* CSS */
a.f-star{text-decoration:none}
a.f-star:hover,a.f-star:focus-visible{color:var(--tx)}
.finding:target .f-title{color:var(--accent)}
@media(prefers-reduced-motion:no-preference){
  .finding:target{animation:f-land 1.4s ease-out 1}
  @keyframes f-land{from{background:color-mix(in srgb,var(--accent) 7%,transparent)}to{background:transparent}}
}

function gotoHash(){
  if(!location.hash) return;
  var t=document.getElementById(decodeURIComponent(location.hash.slice(1)));
  if(t) t.scrollIntoView();
}
/* end of init(): */ gotoHash();
if(document.fonts && document.fonts.ready) document.fonts.ready.then(gotoHash);

/* renderFooter, before the credit <p> */
var nav=el("p","foot-nav");
var a1=el("a",null,"↑ Back to top"); a1.href="#top"; nav.appendChild(a1);
nav.appendChild(el("span","fn-sep","·"));
var a2=el("a",null,"Findings, by principle"); a2.href="#scorecard-sec"; nav.appendChild(a2);
col.appendChild(nav);
/* CSS */
.foot-nav{margin:0 0 1.4rem}
.foot-nav a{font:500 .68rem/1 "Fira Code",monospace; letter-spacing:.12em; text-transform:uppercase; color:var(--tx-2); text-decoration:none}
.foot-nav a:hover,.foot-nav a:focus-visible{color:var(--accent)}
.foot-nav .fn-sep{color:var(--ui-3); padding:0 .6rem}
